# upload any file type to a folder
def allowed_file(filename):

    # check if the file type is allowed, based on app.config['UPLOAD_EXTENSIONS'] value
    return '.' in filename and \
           filename.rsplit('.', 1)[1] in app.config['ALLOWED_EXTENSIONS']


